import base64
import zlib
import requests
import uuid
import datetime

def create_saml_authn_request(destination_url, user_info):
    saml_request_template = '''<samlp:AuthnRequest xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol" 
                                    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
                                    ID="{id}" Version="2.0" IssueInstant="{issue_instant}" 
                                    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST" 
                                    AssertionConsumerServiceURL="{acs_url}" Destination="{destination}">
        <saml:Issuer>{issuer}</saml:Issuer>
        <samlp:NameIDPolicy Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress" AllowCreate="true"/>
    </samlp:AuthnRequest>'''

    authn_request = saml_request_template.format(
        id='_' + uuid.uuid4().hex,
        issue_instant=datetime.datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ'),
        acs_url=user_info['acs_url'],
        destination=destination_url,
        issuer=user_info['issuer']
    )

    def encode_request(saml_request):
        compressed_request = zlib.compress(saml_request.encode('utf-8'))[2:-4]
        return base64.b64encode(compressed_request).decode('utf-8')

    encoded_saml_request = encode_request(authn_request)

    response = requests.post(destination_url, data={
        'SAMLRequest': encoded_saml_request
    })

    return response.content

# Example usage
